ptions used for span creation\n   * @param [context] Context to use to extract parent\n   * @param fn function called in the context of the span and receives the newly created span as an argument\n   * @returns return value of fn\n   * @example\n   *     const something = tracer.startActiveSpan('op', span => {\n   *       try {\n   *         do some work\n   *         span.setStatus({code: SpanStatusCode.OK});\n   *         return something;\n   *       } catch (err) {\n   *         span.setStatus({\n   *           code: SpanStatusCode.ERROR,\n   *           message: err.message,\n   *         });\n   *         throw err;\n   *       } finally {\n   *         span.end();\n   *       }\n   *     });\n   *\n   * @example\n   *     const span = tracer.startActiveSpan('op', span => {\n   *       try {\n   *         do some work\n   *         return span;\n   *       } catch (err) {\n   *         span.setStatus({\n   *           code: SpanStatusCode.ERROR,\n   *           message: err.message,\n   *         });\n   *         throw err;\n   *       }\n   *     });\n   *     do some more work\n   *     span.end();\n   */\n  startActiveSpan<F extends (span: Span) => unknown>(\n    name: string,\n    fn: F\n  ): ReturnType<F>;\n  startActiveSpan<F extends (span: Span) => unknown>(\n    name: string,\n    options: SpanOptions,\n    fn: F\n  ): ReturnType<F>;\n  startActiveSpan<F extends (span: Span) => unknown>(\n    name: string,\n    options: SpanOptions,\n    context: Context,\n    fn: F\n  ): ReturnType<F>;\n}\n"]}
