e227cd48  // coverage.
a2c23396  //
36147d2e  // Plan 03-03 (not this plan) will wire these helpers into the
d84ea0e2  // before_provider_request hook for live chat spans. This file ships the
97919307  // skeleton + unit-testable signatures.
e3b0c442  
00be0592  import { SpanKind, trace, type Span, type Tracer } from "@opentelemetry/api";
e3b0c442  
65b3d7fa  export interface ProfileRef {
15911e21  	id: string;
64382b3d  	version: string;
3e917e59  	hash: string;
d10b36aa  }
e3b0c442  
69166c80  export interface StartChatSpanArgs {
139f1edd  	model: string;
5cc02d20  	profile: ProfileRef;
0e5f2302  	promptSha256: string;
d42dadb9  	/** Optional override; defaults to global trace.getTracer("emmy", ...) */
e1918d01  	tracer?: Tracer;
d10b36aa  }
