8d64a30d  /**
242ade5e   * Start an OTel GenAI semconv chat span with emmy-specific extensions.
64e75266   *
c2179bc0   * Attribute schema:
ec37d654   *   gen_ai.system               = "vllm"
49f1e61c   *   gen_ai.request.model        = args.model
d2dd4718   *   emmy.prompt.sha256          = args.promptSha256
8ec137ec   *   emmy.profile.{id,ver,hash}  = auto-stamped by SpanProcessor.onStart
64e75266   *
2629a65b   * Caller is responsible for ending the span (via endChatSpan) to ensure
e12a0484   * duration + finish-reason metrics land on the right span.
533a9f11   */
1a33dac4  export function startChatSpan(args: StartChatSpanArgs): Span {
6797038c  	const tracer = args.tracer ?? trace.getTracer("emmy", "0.1.0");
b8fa55be  	const span = tracer.startSpan("emmy.chat", { kind: SpanKind.CLIENT });
c7028330  	span.setAttributes({
95e3d7ae  		"gen_ai.system": "vllm",
78817668  		"gen_ai.request.model": args.model,
7907537b  		"emmy.prompt.sha256": args.promptSha256,
eeb33785  	});
