64e75266   *
c2179bc0   * Attribute schema:
520b9de2   *   gen_ai.operation.name = "execute_tool"
60c885f0   *   gen_ai.tool.name      = args.toolName
d506ee22   *   emmy.tool.args_hash   = args.argsHash
533a9f11   */
3d843731  export function startToolExecuteSpan(args: StartToolExecuteSpanArgs): Span {
6797038c  	const tracer = args.tracer ?? trace.getTracer("emmy", "0.1.0");
55e05ff3  	const span = tracer.startSpan(`emmy.tool.${args.toolName}`, { kind: SpanKind.INTERNAL });
c7028330  	span.setAttributes({
d8170821  		"gen_ai.operation.name": "execute_tool",
8bca2990  		"gen_ai.tool.name": args.toolName,
fc6eb8d1  		"emmy.tool.args_hash": args.argsHash,
eeb33785  	});
a4a890cf  	return span;
d10b36aa  }
e3b0c442  
f31d4bfd  export interface EndChatSpanArgs {
