48409184  	tokensOut?: number;
de4ce4bc  	finishReasons?: string[];
d10b36aa  }
e3b0c442  
8d64a30d  /**
c447ccc4   * Stamp usage + finish-reason attrs and end a chat span. Idempotent on the
12189ee9   * close side — subsequent end() calls are cheap no-ops per OTel SDK.
533a9f11   */
4c4cb4aa  export function endChatSpan(span: Span, args: EndChatSpanArgs): void {
dda33c5d  	if (args.tokensIn !== undefined) span.setAttribute("gen_ai.usage.input_tokens", args.tokensIn);
227bd927  	if (args.tokensOut !== undefined) span.setAttribute("gen_ai.usage.output_tokens", args.tokensOut);
